gP_(){return"\u0417\u0430\u043c\u0435\u043d\u0438\u0442\u044c \u0442\u0435\u043a\u0443\u0449\u0443\u044e \u043a\u043e\u043b\u043b\u0435\u043a\u0446\u0438\u044e?"},
gOY(){return"\u0422\u0435\u043a\u0443\u0449\u0430\u044f \u043a\u043e\u043b\u043b\u0435\u043a\u0446\u0438\u044f \u043d\u0435 \u043f\u0443\u0441\u0442\u0430. \u041f\u0440\u0438 \u0438\u043c\u043f\u043e\u0440\u0442\u0435 \u0442\u0435\u043a\u0443\u0449\u0438\u0435 \u0434\u0430\u043d\u043d\u044b\u0435 \u0431\u0443\u0434\u0443\u0442 \u0443\u0434\u0430\u043b\u0435\u043d\u044b \u0438 \u0437\u0430\u043c\u0435\u043d\u0435\u043d\u044b \u0441\u043e\u0434\u0435\u0440\u0436\u0438\u043c\u044b\u043c \u0444\u0430\u0439\u043b\u0430."},
gOZ(){return"\u0417\u0430\u043c\u0435\u043d\u0438\u0442\u044c"},
gOW(){return"\u041a\u0430\u0440\u0442\u044b \u043d\u0435 \u043d\u0430\u0439\u0434\u0435\u043d\u044b"},
OV(a){return"\u042d\u0442\u0438 \u043a\u0430\u0440\u0442\u044b \u043e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u044e\u0442 \u0432 \u043a\u0430\u0442\u0430\u043b\u043e\u0433\u0435 \u0438 \u043d\u0435 \u0431\u044b\u043b\u0438 \u0438\u043c\u043f\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u0430\u043d\u044b:\n\n"+a},
gP2(){return"\u041f\u043e\u0434\u0435\u043b\u0438\u0442\u044c\u0441\u044f ZIP \u0441 \u043d\u043e\u0432\u044b\u043c\u0438 \u0441\u043a\u0430\u0447\u0430\u043d\u043d\u044b\u043c\u0438 \u043a\u0430\u0440\u0442\u0438\u043d\u043a\u0430\u043c\u0438"},
gP4(){return"\u041a\u043e\u043b\u043b\u0435\u043a\u0446\u0438\u044f \u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u0435\u043b\u044f"},
gP3(){return"\u041f\u0440\u043e\u0441\u0442\u043e\u0439 \u0444\u043e\u0440\u043c\u0430\u0442 \u0444\u0430\u0439\u043b\u0430: \u043e\u0434\u043d\u0430 \u043a\u0430\u0440\u0442\u0430 \u043d\u0430 \u0441\u0442\u0440\u043e\u043a\u0443 -> \u043a\u0430\u0440\u0442\u0430:\u0443\u0440\u043e\u0432\u0435\u043d\u044c"},
gP1(){return"\u041f\u043e\u0434\u0435\u043b\u0438\u0442\u044c\u0441\u044f \u043a\u043e\u043b\u043b\u0435\u043a\u0446\u0438\u0435\u0439 (TXT)"},
gOT(){return"\u0418\u043c\u043f\u043e\u0440\u0442 \u043a\u043e\u043b\u043b\u0435\u043a\u0446\u0438\u0438 \u0438\u0437 TXT"},
