gOR(){return"\u042d\u043a\u0441\u043f\u043e\u0440\u0442 \u043d\u0430\u0441\u0442\u0440\u043e\u0435\u043a \u043a\u043e\u043b\u043e\u0434 (JSON)"},
gOU(){return"\u0418\u043c\u043f\u043e\u0440\u0442 \u043d\u0430\u0441\u0442\u0440\u043e\u0435\u043a \u043a\u043e\u043b\u043e\u0434 (JSON)"},
gON(){return"\u042d\u043a\u0441\u043f\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0432\u0441\u0435 \u043a\u043e\u043b\u043e\u0434\u044b"},
OO(a){return'\u042d\u043a\u0441\u043f\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u0430\u0442\u044c "'+a+'"'},
gGe(){return"\u041a\u0430\u0442\u0430\u043b\u043e\u0433 \u043a\u043e\u043c\u0431\u0438\u043d\u0430\u0446\u0438\u0439"},
gGm(){return"\u0421\u0438\u043d\u0442\u0435\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u044b Fusion (\u043e\u043d\u0438\u043a\u0441)"},
gGl(){return"\u0414\u043e\u0431\u0430\u0432\u043b\u044f\u0435\u0442 \u043e\u043d\u0438\u043a\u0441-\u043a\u043e\u043f\u0438\u0438 \u0441 \u0443\u0441\u0438\u043b\u0435\u043d\u043d\u044b\u043c\u0438 \u0410/\u0417 \u0438 \u0434\u043e\u043f\u043e\u043b\u043d\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0435 \u0441\u0442\u0440\u043e\u043a\u0438 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u043e\u0432 \u0434\u043b\u044f \u0434\u0432\u0443\u0445 \u043e\u043d\u0438\u043a\u0441-\u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u043e\u0432."},
gGg(){return"\u0424\u0430\u0439\u043b\u044b"},
gGf(){return"\u0418\u043c\u043f\u043e\u0440\u0442/\u044d\u043a\u0441\u043f\u043e\u0440\u0442 \u0434\u0430\u043d\u043d\u044b\u0445, \u043f\u0430\u0442\u0447\u0435\u0439 \u0438 \u0441\u0435\u0440\u0432\u0438\u0441\u043d\u044b\u0445 \u0444\u0430\u0439\u043b\u043e\u0432 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u044f."},
gGk(){return"\u041e\u0442\u043a\u0440\u044b\u0442\u044c \u044d\u043a\u0440\u0430\u043d \u0444\u0430\u0439\u043b\u043e\u0432"},
gGa(){return"\u0420\u0430\u0437\u0431\u0438\u0432\u043a\u0430 \u043f\u043e \u0430\u0431\u0438\u043b\u043a\u0435 \u0438 \u0440\u0435\u0434\u043a\u043e\u0441\u0442\u0438"},
gGb(){return"\u0411\u0435\u0437 \u0430\u0431\u0438\u043b\u043a\u0438"},
gCS(){return"\u0410\u0442\u0430\u043a\u0430"},
gCT(){return"\u0417\u0430\u0449\u0438\u0442\u0430"},
gCU(){return"\u0421\u0443\u043c\u043c\u0430 \u0441\u0442\u0430\u0442\u043e\u0432"},
Nj(a,b,c){return a+" \xb7 \u0440\u0430\u0437\u043c\u0435\u0440 "+b+" \xb7 \u0441\u0442\u0430\u0440\u0442: "+c},
gNh(){return"\u043d\u0435 \u0432\u044b\u0431\u0440\u0430\u043d\u043e"},
gN5(){return"\u0414\u043e\u0431\u0430\u0432\u044c\u0442\u0435 \u0445\u043e\u0442\u044f \u0431\u044b \u043e\u0434\u043d\u0443 \u043a\u043e\u043c\u0431\u043e-\u043a\u0430\u0440\u0442\u0443 \u0432 \u043a\u043e\u043b\u043b\u0435\u043a\u0446\u0438\u044e."},
