gMV(){return"0 - \u0442\u043e\u043b\u044c\u043a\u043e \u0432\u044b\u0431\u0440\u0430\u043d\u043d\u044b\u0435 \u0441\u0442\u0430\u0442\u044b, 1 - \u0442\u043e\u043b\u044c\u043a\u043e \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u043e \u043a\u043e\u043c\u0431\u0438\u043d\u0430\u0446\u0438\u0439"},
MS(a){return"\u0411\u0430\u043b\u0430\u043d\u0441 \u043a\u043e\u043c\u0431\u043e / \u0441\u043b\u0443\u0447\u0430\u0439\u043d\u0430\u044f \u0440\u0443\u043a\u0430: "+a},
gMT(){return"0 \u2014 \u0442\u043e\u043b\u044c\u043a\u043e \u043f\u0430\u0440\u044b \u0438 \u043a\u043e\u043c\u0431\u043e (\u0441\u0442\u0430\u0442\u044b/\u043a\u043e\u043c\u0431\u043e \u0432\u044b\u0448\u0435), 1 \u2014 \u0442\u043e\u043b\u044c\u043a\u043e \u043e\u0436\u0438\u0434\u0430\u0435\u043c\u0430\u044f \u0441\u0438\u043b\u0430 \u0441\u043b\u0443\u0447\u0430\u0439\u043d\u043e\u0439 \u0440\u0443\u043a\u0438 \u0438\u0437 5 \u043a\u0430\u0440\u0442 \u043f\u043e \u0442\u0438\u0440\u0443"},
