PL(a){return"\u0424\u0430\u0439\u043b \u043d\u0435 \u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0432\u0430\u043b\u0438\u0434\u043d\u044b\u043c JSON: "+A.k(a)},
PT(a){return"\u041f\u0430\u0442\u0447 \u0441\u043e\u0445\u0440\u0430\u043d\u0435\u043d; \u043a\u0430\u0442\u0430\u043b\u043e\u0433 \u043f\u0435\u0440\u0435\u0441\u043e\u0431\u0440\u0430\u043d ("+a+" \u043a\u0430\u0440\u0442)"},
