gym(){return"\u041e\u0442\u043a\u0440\u044b\u0442 \u0441\u0438\u0441\u0442\u0435\u043c\u043d\u044b\u0439 \u044d\u043a\u0440\u0430\u043d \u041f\u043e\u0434\u0435\u043b\u0438\u0442\u044c\u0441\u044f. \u0412\u044b\u0431\u0435\u0440\u0438\u0442\u0435 \u0421\u043e\u0445\u0440\u0430\u043d\u0438\u0442\u044c \u0432 \u0424\u0430\u0439\u043b\u044b \u0438 \u043f\u0430\u043f\u043a\u0443 \u043d\u0430\u0437\u043d\u0430\u0447\u0435\u043d\u0438\u044f."},
